// ══════════════════════════════════════════════════════════════
// WF-02 — CONFIGURACIÓN GLOBAL
// ══════════════════════════════════════════════════════════════

// Vertical activo para esta ejecución
// Rotar semanalmente: 'financiero' → 'retail' → 'manufactura'
const VERTICAL_ACTIVO = 'financiero';

// Tamaño de lista por ejecución
const PAGE_SIZE = 25; // Lusha max 50 por request
const PAGINAS    = 4;  // 4 páginas × 25 = 100 contactos/semana

// Instantly — campaña ID por vertical (llenar tras crear campañas en Instantly)
const INSTANTLY_CAMPAIGNS = {
  financiero:  'INSTANTLY_CAMPAIGN_ID_FINANCIERO',
  retail:      'INSTANTLY_CAMPAIGN_ID_RETAIL',
  manufactura: 'INSTANTLY_CAMPAIGN_ID_MANUFACTURA',
  salud:       'INSTANTLY_CAMPAIGN_ID_SALUD',
  gobierno:    'INSTANTLY_CAMPAIGN_ID_GOBIERNO'
};

// Filtros Lusha por vertical
const VERTICAL_CONFIG = {
  financiero: {
    label: 'Financiero / Seguros',
    framework: 'PAS',
    jobTitles: ['CTO', 'Director TI', 'Director Tecnología', 'VP Tecnología', 'Gerente TI', 'Chief Technology Officer'],
    industries: ['Financial Services', 'Insurance', 'Banking'],
    companySize: [{ min: 200, max: 5000 }]
  },
  retail: {
    label: 'Retail / eCommerce',
    framework: 'AIDA',
    jobTitles: ['CTO', 'Director Digital', 'CDO', 'Director Transformación Digital', 'eCommerce Director'],
    industries: ['Retail', 'Consumer Goods'],
    companySize: [{ min: 500, max: 10000 }]
  },
  manufactura: {
    label: 'Manufactura / Industrial',
    framework: 'BEFORE_AFTER',
    jobTitles: ['CTO', 'Director TI', 'Director Operaciones', 'COO', 'Director Manufactura'],
    industries: ['Manufacturing', 'Industrial Machinery', 'Automotive'],
    companySize: [{ min: 300, max: 5000 }]
  },
  salud: {
    label: 'Salud / Healthcare',
    framework: 'CASE_STUDY',
    jobTitles: ['Director TI', 'CTO', 'Director Transformación Digital', 'Director Médico Informático'],
    industries: ['Healthcare', 'Hospital & Health Care', 'Medical Devices'],
    companySize: [{ min: 200, max: 3000 }]
  },
  gobierno: {
    label: 'Gobierno / Sector Público',
    framework: 'PAS_NORMATIVO',
    jobTitles: ['Director General TI', 'Director Informática', 'Subdirector TI', 'Director Transformación Digital'],
    industries: ['Government Administration', 'Public Sector'],
    companySize: [{ min: 100, max: 10000 }]
  }
};

const config = VERTICAL_CONFIG[VERTICAL_ACTIVO];

return [{
  json: {
    vertical: VERTICAL_ACTIVO,
    verticalLabel: config.label,
    framework: config.framework,
    jobTitles: config.jobTitles,
    industries: config.industries,
    companySize: config.companySize,
    pageSize: PAGE_SIZE,
    totalPages: PAGINAS,
    campaignId: INSTANTLY_CAMPAIGNS[VERTICAL_ACTIVO],
    currentPage: 0
  }
}];

