// ══════════════════════════════════════════════════════════════
// DEDUP + LIMPIEZA DE LISTA
// ══════════════════════════════════════════════════════════════
// Filtra contactos sin email, ya en Pipedrive, o duplicados en esta ejecución

const contacts = $input.all();
const seen = new Set();
const clean = [];

for (const item of contacts) {
  const c = item.json;

  // Requiere email válido
  if (!c.email || !c.email.includes('@')) continue;

  // Dedup por email en esta ejecución
  if (seen.has(c.email)) continue;
  seen.add(c.email);

  // Requiere nombre y empresa
  if (!c.firstName || !c.companyName) continue;

  clean.push({
    json: {
      lusha_id:      c.id,
      first_name:    c.firstName,
      last_name:     c.lastName || '',
      email:         c.email,
      title:         c.title || '',
      company_name:  c.companyName,
      company_size:  c.companySize || '',
      industry:      c.industry || '',
      linkedin_url:  c.linkedinUrl || '',
      phone:         c.phone || '',
      city:          c.city || '',
      country:       c.country || 'México',
      // pasamos el vertical desde el primer nodo config
      vertical:      $('Config — Vertical y Parámetros').first().json.vertical,
      verticalLabel: $('Config — Vertical y Parámetros').first().json.verticalLabel,
      framework:     $('Config — Vertical y Parámetros').first().json.framework,
      campaign_id:   $('Config — Vertical y Parámetros').first().json.campaignId
    }
  });
}

return clean;

// ══════════════════════════════════════════════════════════════
// BUILD PROMPT PARA CLAUDE — Copy A/B por vertical
// ══════════════════════════════════════════════════════════════

const FRAMEWORK_INSTRUCTIONS = {
  PAS: `Framework PAS (Problem-Agitate-Solution) para sector Financiero/Seguros:
1. PROBLEM (1-2 líneas): Nombrar un problema específico del sector (legacy systems, regulación CNBV/CNSF, integraciones core bancario, tiempo de TTM)
2. AGITATE (1-2 líneas): Consecuencia real de no resolver
3. SOLUTION (1-2 líneas): Cómo Bambu lo resuelve sin vender, solo mostrando el camino
Ejemplo de asunto: "integración core bancario sin reemplazarlo"`,

  AIDA: `Framework AIDA (Attention-Interest-Desire-Action) para sector Retail/eCommerce:
1. ATTENTION (1 línea): Dato o pregunta que interrumpa — específico para retail mexicano
2. INTEREST (1-2 líneas): Contexto relevante para la empresa del contacto
3. DESIRE (1-2 líneas): Resultado concreto de un cliente similar (Bonafont, Office Depot)
4. ACTION (1 línea): Una sola pregunta para abrir conversación
Ejemplo de asunto: "inventario unificado en línea y tienda física"`,

  BEFORE_AFTER: `Framework Before-After para Manufactura/Industrial:
1. BEFORE (1-2 líneas): Situación actual sin resolver — específica para manufactura
2. AFTER (1-2 líneas): Cómo sería diferente con la solución correcta
3. BRIDGE (1 línea): Bambu como el puente entre ambos estados
4. CTA (1 línea): Pregunta concreta sobre su situación actual
Ejemplo de asunto: "datos de planta en tiempo real sin cambiar el ERP"`,

  CASE_STUDY: `Framework Case Study para Sector Salud:
1. CONTEXTO (1 línea): Presentar brevemente un caso análogo
2. PROBLEMA que tenía ese cliente (1 línea)
3. LO QUE HIZO Bambu (1-2 líneas, técnico pero entendible)
4. RESULTADO (1 línea con métrica si es posible)
5. CONEXIÓN (1 línea): "En [empresa] podría aplicar algo similar porque..."
6. CTA (1 línea): Pregunta abierta
Ejemplo de asunto: "expediente clínico integrado sin reemplazar el HIS"`,

  PAS_NORMATIVO: `Framework PAS-Normativo para Gobierno/Sector Público:
1. PROBLEM (1-2 líneas): Reto de modernización con restricciones presupuestales o normativas
2. AGITATE (1 línea): Consecuencia (rezago ciudadano, auditorías, cambio de administración)
3. SOLUTION (1-2 líneas): Desarrollo a la medida que respeta marco normativo existente
4. CREDENCIAL (1 línea): Mención a DINA u otro cliente de sector público/industrial
Nota: Tono más formal. Usar "usted". Evitar anglicismos.
Ejemplo de asunto: "modernización sin reemplazar sistemas críticos"`
};

const c = $input.first().json;
const framework = FRAMEWORK_INSTRUCTIONS[c.framework] || FRAMEWORK_INSTRUCTIONS.PAS;

const systemPrompt = `Eres un experto en ventas B2B consultivas para empresas de tecnología en México.
Escribes emails fríos de alta personalización que se sienten como de colega a colega, no como spam corporativo.`;

const userPrompt = `Escribe DOS variantes de email frío (A y B) para el siguiente contacto.

DATOS DEL CONTACTO:
- Nombre: ${c.first_name} ${c.last_name}
- Cargo: ${c.title}
- Empresa: ${c.company_name}
- Tamaño empresa: ${c.company_size} empleados
- Industria: ${c.industry}
- Vertical objetivo: ${c.verticalLabel}
- Ciudad: ${c.city}, ${c.country}

SOBRE BAMBU TECH SERVICES:
Bambu es una empresa mexicana de desarrollo de software a la medida, integraciones estratégicas (SAP, Oracle, Salesforce, sistemas legados), cloud e infraestructura, y soluciones de Data & AI. 10+ años de experiencia, 500+ proyectos entregados. Clientes: Gayosso, Bonafont, Office Depot, GNP Seguros, Farmacia San Pablo, DINA.

CASO DE ÉXITO CLAVE:
Isela Montenegro, Directora de Tecnología de Grupo Gayosso, habla sobre cómo Bambu transformó su operación tecnológica.
Video: https://youtu.be/6y1Jm8M-V38

REGLAS:
- Asunto: máx 8 palabras, sin signos de exclamación
- Cuerpo: máx 120 palabras
- Tono: directo, colega a colega, sin jerga de ventas
- Primera línea: mención específica a ${c.company_name} o al rol de ${c.title}
- NO usar: "espero que estés bien", "me permito escribirte", "a quien corresponda"
- NO mencionar precios ni "soluciones innovadoras"
- Cierre: UNA sola pregunta abierta o CTA específico
- Las dos variantes deben tener enfoques distintos (ángulo diferente del mismo problema)

FRAMEWORK PARA ESTE VERTICAL:
${framework}

RESPUNDE ÚNICAMENTE CON JSON VÁLIDO (sin texto adicional, sin markdown):
{
  "email_a": { "subject": "...", "body": "..." },
  "email_b": { "subject": "...", "body": "..." }
}`;

return [{
  json: {
    ...c,
    claude_system: systemPrompt,
    claude_user: userPrompt
  }
}];

