// ══════════════════════════════════════════════════════════════
// PARSE RESPUESTA DE CLAUDE + MERGE CON DATOS DEL CONTACTO
// ══════════════════════════════════════════════════════════════

const item = $input.first();
const contact = $('Build Prompt Claude').first().json;

let emailA, emailB;
try {
  const raw = item.json.content[0].text;
  // Claude a veces envuelve en ```json ... ```
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  emailA = parsed.email_a;
  emailB = parsed.email_b;
} catch(e) {
  // Si Claude no devuelve JSON válido, log y skip
  return [{ json: { error: true, reason: 'Claude parse error', contact_email: contact.email } }];
}

return [{
  json: {
    // Datos del contacto
    lusha_id:     contact.lusha_id,
    first_name:   contact.first_name,
    last_name:    contact.last_name,
    email:        contact.email,
    title:        contact.title,
    company_name: contact.company_name,
    industry:     contact.industry,
    linkedin_url: contact.linkedin_url,
    phone:        contact.phone,
    vertical:     contact.vertical,
    campaign_id:  contact.campaign_id,
    // Copy generado
    subject_a:    emailA.subject,
    body_a:       emailA.body,
    subject_b:    emailB.subject,
    body_b:       emailB.body,
    // Variante asignada (A/B por paridad del lusha_id)
    variant:      (parseInt(contact.lusha_id) % 2 === 0) ? 'A' : 'B',
    subject_final: (parseInt(contact.lusha_id) % 2 === 0) ? emailA.subject : emailB.subject,
    body_final:    (parseInt(contact.lusha_id) % 2 === 0) ? emailA.body    : emailB.body
  }
}];

