const item = $input.first();
const reply = $('Webhook — Respuesta Instantly').first().json;

let classification;
try {
  const raw = item.json.content[0].text;
  const cleaned = raw.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  classification = JSON.parse(cleaned);
} catch(e) {
  classification = { categoria: 'NEGATIVA', razon: 'Parse error', accion_sugerida: 'Revisar manualmente' };
}

return [{
  json: {
    // Datos del reply de Instantly
    reply_email:    reply.body?.email || reply.email || '',
    reply_text:     reply.body?.reply_text || '',
    campaign_id:    reply.body?.campaign_id || '',
    // Clasificación de Claude
    categoria:       classification.categoria,
    razon:           classification.razon,
    accion:          classification.accion_sugerida,
    referido:        classification.contacto_referido,
    reactivar_dias:  classification.reactivar_en_dias,
    es_positiva:     classification.categoria === 'POSITIVA'
  }
}];

// ══════════════════════════════════════════════════════════════
// ASIGNACIÓN ALEATORIA — Pre Sales
// ══════════════════════════════════════════════════════════════
// Usa hash del email del prospecto para asignación determinista:
// el mismo contacto siempre cae al mismo Pre Sales (evita reasignaciones).

const PRE_SALES = [
  { pipedrive_id: 24060159, nombre: 'Samantha Rivas',  email: 'samantha.rivas@bambu-techservices.com' },
  { pipedrive_id: 25431089, nombre: 'Vicente Varela',  email: 'vicente.varela@bambu-techservices.com' },
  { pipedrive_id: 25752795, nombre: 'Emilio Mendoza',  email: 'emilio.mendoza@bambu-techservices.com' },
  { pipedrive_id: 11865784, nombre: 'Sofia Santiago',  email: 'sofia@bambu-techservices.com'          },
  { pipedrive_id: 26438238, nombre: 'Harold Bautista', email: 'harold.bautista@bambu-techservices.com' }
];

const replyEmail = $json.reply_email || '';

// Hash simple: suma de char codes del email % cantidad de reps
const hash = replyEmail.split('').reduce((acc, ch) => acc + ch.charCodeAt(0), 0);
const assigned = PRE_SALES[hash % PRE_SALES.length];

return [{
  json: {
    ...$json,
    presales_pipedrive_id: assigned.pipedrive_id,
    presales_nombre:       assigned.nombre,
    presales_email:        assigned.email
  }
}];

